/* ─── IMMERSIVE FULL-BLEED DEAL CARD (matches app reels design) ─── */
.live-deals-grid {
  display: grid; grid-template-columns: 1fr;
  gap: 20px; margin-bottom: 48px; justify-items: center;
}
@media (min-width: 700px) {
  .live-deals-grid { grid-template-columns: repeat(2, minmax(0, 420px)); }
}
@media (min-width: 1100px) {
  .live-deals-grid { grid-template-columns: repeat(3, minmax(0, 380px)); }
}
.live-deal-card {
  width: 100%; max-width: 440px;
  border-radius: 18px; overflow: hidden;
  background: #000; border: 1px solid #2A2A2A;
  transition: transform 0.22s, border-color 0.22s, box-shadow 0.22s;
}
.live-deal-card:hover {
  transform: translateY(-5px); border-color: var(--gold-border);
  box-shadow: 0 16px 50px rgba(0,0,0,0.45);
}
.ivx-imm-media {
  position: relative; width: 100%; aspect-ratio: 9 / 16;
  min-height: 520px; max-height: 720px; overflow: hidden;
  background: #141414; contain: layout style;
}
.ivx-imm-media .live-deal-gallery-slider {
  position: absolute; inset: 0; z-index: 1;
}
.ivx-imm-overlay {
  position: absolute; inset: 0; z-index: 2;
  display: flex; flex-direction: column; justify-content: space-between;
  background: linear-gradient(180deg, rgba(0,0,0,0.55) 0%, rgba(0,0,0,0.12) 25%, rgba(0,0,0,0.12) 60%, rgba(0,0,0,0.82) 100%);
  pointer-events: none;
}
.ivx-imm-top {
  display: flex; justify-content: space-between; align-items: flex-start; gap: 12px;
  padding: 14px; pointer-events: auto;
}
.ivx-imm-badges { display: flex; gap: 8px; flex-wrap: wrap; }
.ivx-imm-badge {
  border-radius: 8px; padding: 5px 10px;
  font-size: 10px; font-weight: 900; letter-spacing: 0.8px; text-transform: uppercase;
}
.ivx-imm-badge-filled { background: var(--gold); color: #000; }
.ivx-imm-badge-outline { background: transparent; color: var(--gold); border: 1.5px solid var(--gold); }
.ivx-imm-actions-right {
  display: flex; flex-direction: column; align-items: center; gap: 10px;
}
.ivx-imm-icon {
  width: 42px; height: 42px; border-radius: 50%;
  background: rgba(0,0,0,0.45); border: 1px solid rgba(255,255,255,0.18);
  color: #fff; font-size: 18px; display: flex; align-items: center; justify-content: center;
  cursor: pointer; backdrop-filter: blur(6px); -webkit-backdrop-filter: blur(6px);
  transition: transform 0.15s, background 0.2s; pointer-events: auto;
}
.ivx-imm-icon:hover { background: rgba(0,0,0,0.65); transform: scale(1.08); }
.ivx-imm-bottom {
  padding: 14px; padding-top: 40px; pointer-events: auto;
}
.ivx-imm-title-block { margin-bottom: 12px; }
.ivx-imm-title {
  font-size: 22px; font-weight: 900; color: #fff; line-height: 1.1; margin-bottom: 3px;
  text-shadow: 0 1px 6px rgba(0,0,0,0.45);
}
.ivx-imm-subtitle {
  font-size: 14px; font-weight: 700; color: #fff; margin-bottom: 2px;
  text-shadow: 0 1px 4px rgba(0,0,0,0.45);
}
.ivx-imm-loc {
  font-size: 12px; color: rgba(255,255,255,0.82); display: flex; align-items: center; gap: 4px;
}
.ivx-imm-stats {
  display: flex; gap: 16px; margin-bottom: 14px;
}
.ivx-imm-stat { display: flex; align-items: baseline; gap: 4px; }
.ivx-imm-stat-v { font-size: 16px; font-weight: 900; color: var(--gold); }
.ivx-imm-stat-l { font-size: 10px; font-weight: 700; color: rgba(255,255,255,0.7); text-transform: uppercase; letter-spacing: 0.5px; }
.ivx-imm-actions-row {
  display: flex; align-items: center; gap: 8px; flex-wrap: wrap; margin-bottom: 14px;
}
