  var verifiedCount = 0;
  if (trustInfo.titleVerified) verifiedCount++;
  if (trustInfo.insuranceCoverage) verifiedCount++;
  if (trustInfo.escrowProtected) verifiedCount++;
  if (trustInfo.permitStatus === 'approved') verifiedCount++;
  if (trustInfo.thirdPartyAudit) verifiedCount++;
  var verifiedBadgeHtml = verifiedCount >= 3 ? '<div class="live-deal-verified-badge"><svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="#22C55E" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg> VERIFIED</div>' : '';
  var photoSourceBadgeHtml = getPhotoSourceBadgeHtml(deal.photoSource || (photos.length > 0 ? 'db' : 'none'));
  var salePrice = getDealSalePrice(deal, trustInfo);
  var minInvestment = getDealMinInvestment(deal, trustInfo);
  var shareEntryPrice = getDealFractionalSharePrice(deal, trustInfo, minInvestment);
