  var minimumOwnershipLabel = getMinimumOwnershipLabel(minInvestment, salePrice);
  var location = getDealAddressShort(deal);
  var developerName = getDealDeveloperName(deal, trustInfo);
  var showEntryPill = Math.abs(shareEntryPrice - minInvestment) > 0.009;
