  var slideTotal = dealVideos.length + photos.length;
  if (slideTotal > 0) {
    var sliderId = 'slider-' + (deal.id || Math.random().toString(36).substr(2, 6));
    var imgsHtml = '';
    for (var dvi = 0; dvi < dealVideos.length; dvi++) {
      var dv = dealVideos[dvi] || {};
      var dvSrc = typeof dv === 'string' ? dv : (dv.video_url || dv.url || '');
      if (!dvSrc) continue;
      var dvPoster = typeof dv === 'string' ? '' : (dv.thumbnail_url || dv.cover_url || '');
      imgsHtml += '<video ' + (/\.m3u8($|\?)/.test(dvSrc) ? 'data-hls="' + dvSrc + '"' : 'src="' + dvSrc + '"') + (dvPoster ? ' poster="' + dvPoster + '"' : '') + ' data-igplay="1" preload="metadata" muted loop playsinline controls controlslist="nodownload noremoteplayback" style="min-width:100%;width:100%;height:100%;object-fit:cover;scroll-snap-align:start;flex:0 0 100%;background:#000;"></video>';
    }
