    }
    var dotsHtml = '';
    if (slideTotal > 1) {
      dotsHtml = '<div class="live-deal-photo-dots" data-slider="' + sliderId + '">';
      for (var di = 0; di < slideTotal; di++) {
        dotsHtml += '<div class="live-deal-photo-dot' + (di === 0 ? ' active' : '') + '" data-idx="' + di + '"></div>';
      }
      dotsHtml += '</div>';
    }
    galleryHtml = '<div class="live-deal-gallery" style="position:relative;">' +
