      photoSourceBadgeHtml + verifiedBadgeHtml +
      (slideTotal > 1 ? '<div class="live-deal-photo-count">1/' + slideTotal + '</div>' : '') +
      dotsHtml +
      '</div>';
  } else {
    var dealTitle = escapeHtml((deal.title || 'Deal').toUpperCase());
    var dealSubtitle = escapeHtml(location ? location + ' · ' + formatCurrency(Number(deal.totalInvestment || deal.total_investment || 0)) : formatCurrency(Number(deal.totalInvestment || deal.total_investment || 0)));
    galleryHtml = '<div class="live-deal-gallery" style="position:relative;">' +
