    + '</div>';

  var vid = card.querySelector('video');
  var img = card.querySelector('.ivx-hf-media img');
  var muteBtn = card.querySelector('.ivx-hf-mute');
  muteBtn.addEventListener('click', function () {
    vid.muted = !vid.muted;
    muteBtn.innerHTML = vid.muted ? '&#128263;' : '&#128266;';
  });

